#!/usr/bin/env python3
"""
Fixes the layout issues you flagged:
  - Header buttons ("Download a backup copy", "Recover from a file...",
    "Add destination") were crammed into one row against the title/subtitle.
    Now: title row on top, action buttons on their own row below, with
    secondary actions (Download/Recover) grouped on the left and the primary
    "Add destination" button on the right, wrapping cleanly on narrow widths.
  - The run-history table's Size column was getting clipped off-screen --
    the table now scrolls horizontally instead of overflowing, the date
    column uses a shorter format, and long error messages wrap instead of
    stretching the table wide.
  - The per-destination header (Recover.../Run now/Remove) now wraps too,
    instead of assuming there's always room for all three buttons plus a
    long destination name on one line.

Run from the repo root:
    python3 apply-backups-layout-fix.py

Full-file overwrite of this one file -- supersedes its content from
apply-metadata-tags-folders-download.py, no need to re-run that first.
"""
import base64
from pathlib import Path

FILES = {
    "apps/papra-client/src/modules/backups/pages/backups.page.tsx": "",
}

def main():
    for path_str, b64_content in FILES.items():
        path = Path(path_str)
        content = base64.b64decode(b64_content).decode("utf-8")
        path.write_text(content)
        print(f"\u2714 wrote {path} ({len(content)} bytes)")
    print("\nDone. Restart pnpm dev and hard-refresh the client.")

if __name__ == "__main__":
    main()
